SELECT A.*, B.* FROM( SELECT tt1.rnum no, tt1.user_id, tt1.name, tt1.password, tt1.login, tt1.recommend, tt1.email, DECODE(tt1.grade,1,'BASIC' ,2,'SILVER' ,3,'GOLD') grade, TO_CHAR(tt1.reg_dt,'YYYY/MM/DD') reg_dt FROM( SELECT ROWNUM rnum, t1.* FROM ( SELECT * FROM member
ORDER BY reg_dt DESC )t1 WHERE ROWNUM <= ( #{pageSize} * (#{pageNo} -1) + #{pageSize} ) )tt1 WHERE rnum >= ( #{pageSize} * (#{pageNo} -1) + 1 ) ) A CROSS JOIN( SELECT COUNT(*) total_cnt FROM member
) B
